### Swift Polymorphism

Polymorphism allows objects of different types to be treated as objects of a common superclass. It enables writing generic code that works with any type that shares a common interface.

**Polymorphism with Classes:**

```swift
class Animal {
    func speak() -> String {
        return "..."
    }
}

class Dog: Animal {
    override func speak() -> String {
        return "Woof!"
    }
}

class Cat: Animal {
    override func speak() -> String {
        return "Meow!"
    }
}

// Polymorphic array
let animals: [Animal] = [Dog(), Cat(), Animal()]

// Each object calls its own implementation
for animal in animals {
    print(animal.speak())  // Woof!, Meow!, ...
}
```

**Polymorphism with Protocols:**

```swift
protocol Drawable {
    func draw() -> String
}

struct Circle: Drawable {
    func draw() -> String {
        return "Drawing a circle"
    }
}

struct Square: Drawable {
    func draw() -> String {
        return "Drawing a square"
    }
}

// Polymorphic function
func render(_ items: [Drawable]) {
    for item in items {
        print(item.draw())
    }
}

render([Circle(), Square()])
```

**Type Checking and Casting:**

| Operator | Description |
|----------|-------------|
| `is` | Type check: returns Bool |
| `as?` | Conditional downcast (optional) |
| `as!` | Force downcast (crashes if wrong) |
| `as` | Upcast (always succeeds) |

```swift
let mediaItems: [Any] = ["Hello", 42, Dog(), 3.14]

for item in mediaItems {
    if let string = item as? String {
        print("String with length \(string.count)")
    } else if let number = item as? Int {
        print("Integer: \(number)")
    } else if let animal = item as? Animal {
        print("Animal says: \(animal.speak())")
    }
}
```

> **Key Point:** Polymorphism lets you write code that works with a family of related types. The exact method called is determined at runtime (dynamic dispatch).

Use `Any` and `AnyObject` for heterogeneous collections:
- `Any` can represent any type (including function types)
- `AnyObject` can represent any class type only

codeExample:
import Foundation

protocol Payable {
    func calculatePay() -> Double
}

class Employee {
    var name: String
    init(name: String) { self.name = name }
}

class SalariedEmployee: Employee, Payable {
    var salary: Double
    init(name: String, salary: Double) {
        self.salary = salary
        super.init(name: name)
    }
    func calculatePay() -> Double {
        return salary / 12
    }
}

class HourlyEmployee: Employee, Payable {
    var hourlyRate: Double
    var hoursWorked: Double
    init(name: String, rate: Double, hours: Double) {
        self.hourlyRate = rate
        self.hoursWorked = hours
        super.init(name: name)
    }
    func calculatePay() -> Double {
        return hourlyRate * hoursWorked
    }
}

let employees: [Payable] = [
    SalariedEmployee(name: "Alice", salary: 60000),
    HourlyEmployee(name: "Bob", rate: 25, hours: 160)
]

let totalPayroll = employees.reduce(0) { $0 + $1.calculatePay() }
print("Total payroll: $\(String(format: "%.2f", totalPayroll))")
